/**
 * LeadService gerencia a integração com Web3Forms e validações.
 */
export class LeadService {
  // Chave de demonstração/produção. Certifique-se de que esta chave é válida e permite o domínio atual.
  private static readonly WEB3FORMS_KEY = "5bdef52f-1212-45a3-8ea3-07a06ae8d2ee";
  private static readonly API_ENDPOINT = "https://api.web3forms.com/submit";

  /**
   * Converte uma imagem para PDF de forma assíncrona com otimização.
   */
  private static async convertImageToPdf(file: File): Promise<File> {
    try {
      const { jsPDF } = await import('jspdf');

      return new Promise((resolve, reject) => {
        const reader = new FileReader();
        reader.onload = (e) => {
          const img = new Image();
          img.onload = () => {
            // Otimização agressiva: Max 1200px para garantir envio rápido em 3G/4G
            const MAX_DIMENSION = 1200;
            let width = img.width;
            let height = img.height;

            if (width > MAX_DIMENSION || height > MAX_DIMENSION) {
              const ratio = Math.min(MAX_DIMENSION / width, MAX_DIMENSION / height);
              width *= ratio;
              height *= ratio;
            }

            const canvas = document.createElement('canvas');
            canvas.width = width;
            canvas.height = height;
            const ctx = canvas.getContext('2d');

            if (!ctx) {
              reject(new Error("Erro ao criar contexto de canvas"));
              return;
            }

            ctx.drawImage(img, 0, 0, width, height);

            // Qualidade 0.6 para arquivos leves
            const optimizedDataUrl = canvas.toDataURL('image/jpeg', 0.6);

            const doc = new jsPDF({
              orientation: width > height ? 'landscape' : 'portrait',
              unit: 'px',
              format: [width, height]
            });

            doc.addImage(optimizedDataUrl, 'JPEG', 0, 0, width, height);
            const pdfBlob = doc.output('blob');

            const cleanName = file.name.replace(/[^a-zA-Z0-9]/g, "_");
            const pdfFileName = `${cleanName}_${Date.now()}.pdf`;

            const pdfFile = new File([pdfBlob], pdfFileName, {
              type: 'application/pdf',
              lastModified: Date.now()
            });

            resolve(pdfFile);
          };
          img.onerror = () => reject(new Error("Falha ao processar imagem"));
          img.src = e.target?.result as string;
        };
        reader.onerror = () => reject(new Error("Falha ao ler arquivo"));
        reader.readAsDataURL(file);
      });
    } catch (err) {
      console.warn("[SISTEMA] Biblioteca PDF não carregou, enviando imagem original.", err);
      throw err;
    }
  }

  /**
   * Envia os dados para o Web3Forms.
   */
  static async submitLead(data: LeadData): Promise<IntegrationResponse> {
    const controller = new AbortController();
    const timeoutId = setTimeout(() => controller.abort(), 45000); // 45s Timeout (Aumentado para upload)

    try {
      const formData = new FormData();
      formData.append("access_key", this.WEB3FORMS_KEY);
      formData.append("subject", `NOVO LEAD (${data.revendedor}): ${data.nome_completo.toUpperCase()}`);

      // CORREÇÃO: "from_name" não deve ser um email para evitar bloqueio de SPAM/DMARC
      formData.append("from_name", "Portal CTNB");

      formData.append("botcheck", ""); 

      formData.append("name", data.nome_completo);
      formData.append("email", data.email);
      formData.append("empresa", data.empresa || "Não informada");
      formData.append("revendedor", data.revendedor);
      formData.append("telefone", data.telefone);

      let attachmentToSend = data.documento;

      // Tenta converter, se falhar usa o original silenciosamente
      if (attachmentToSend && attachmentToSend.type.startsWith('image/')) {
        try {
          attachmentToSend = await this.convertImageToPdf(attachmentToSend);
        } catch (convErr) {
          console.warn("[SISTEMA] Falha na conversão PDF, usando arquivo original.");
          attachmentToSend = data.documento;
        }
      }

      if (attachmentToSend) {
        formData.append("attachment", attachmentToSend);
      }

      formData.append("mensagem", `
        Lead capturado via Portal.
        Revendedor: ${data.revendedor}
        Telefone: ${data.telefone}
        Link: https://wa.me/55${data.telefone.replace(/\D/g, '')}
      `);

      const response = await fetch(this.API_ENDPOINT, {
        method: "POST",
        headers: {
          'Accept': 'application/json' // CORREÇÃO CRÍTICA: Garante que o servidor retorne JSON
        },
        body: formData,
        signal: controller.signal
      });

      clearTimeout(timeoutId);

      // Tratamento robusto de resposta (Evita erro de JSON parse se o servidor devolver HTML/Erro 500)
      const textResponse = await response.text();
      let result;
      try {
        result = JSON.parse(textResponse);
      } catch (e) {
        console.error("Resposta não-JSON do servidor:", textResponse);
        throw new Error(`Erro no servidor (Status ${response.status})`);
      }

      if (response.ok && result.success) {
        return {
          success: true,
          message: `Dados encaminhados com sucesso.`,
          integrationId: result.id
        };
      } else {
        throw new Error(result.message || `Erro: ${response.status}`);
      }
    } catch (error: any) {
      clearTimeout(timeoutId);
      console.error("[SISTEMA] Falha no envio:", error);

      let friendlyMessage = "Falha ao conectar com o servidor.";

      if (error.name === 'AbortError') {
        friendlyMessage = "O envio demorou muito. Verifique sua conexão.";
      } else if (error.message.includes('Status 401')) {
        friendlyMessage = "Erro de Autenticação (Chave Inválida).";
      } else if (error.message.includes('Status 403')) {
        friendlyMessage = "Acesso Negado (Domínio não permitido).";
      }

      return {
        success: false,
        message: friendlyMessage
      };
    }
  }

  static validatePhone(phone: string): boolean {
    const cleanPhone = phone.replace(/\D/g, '');
    return cleanPhone.length >= 10 && cleanPhone.length <= 11;
  }

  static validateEmail(email: string): boolean {
    const re = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
    return re.test(email);
  }
}

import { LeadData, IntegrationResponse } from '../types';

export class LeadService {
  // Chave de produção
  private static readonly WEB3FORMS_KEY = "5bdef52f-1212-45a3-8ea3-07a06ae8d2ee";
  private static readonly API_ENDPOINT = "https://api.web3forms.com/submit";

  /**
   * Comprime a imagem usando Canvas API nativa.
   * Transforma em JPEG leve para garantir envio rápido mesmo em 3G.
   */
  private static async compressImage(file: File): Promise<File> {
    return new Promise((resolve, reject) => {
      const reader = new FileReader();
      reader.readAsDataURL(file);
      reader.onload = (event) => {
        const img = new Image();
        img.src = event.target?.result as string;
        img.onload = () => {
          // Redimensiona para no máximo 1000px (Suficiente para documentos)
          const MAX_WIDTH = 1000;
          const MAX_HEIGHT = 1000;
          let width = img.width;
          let height = img.height;

          if (width > height) {
            if (width > MAX_WIDTH) {
              height *= MAX_WIDTH / width;
              width = MAX_WIDTH;
            }
          } else {
            if (height > MAX_HEIGHT) {
              width *= MAX_HEIGHT / height;
              height = MAX_HEIGHT;
            }
          }

          const canvas = document.createElement('canvas');
          canvas.width = width;
          canvas.height = height;
          const ctx = canvas.getContext('2d');

          if (!ctx) {
            resolve(file); // Fallback se canvas falhar
            return;
          }

          ctx.drawImage(img, 0, 0, width, height);

          // Qualidade 0.7 = Bom equilíbrio entre legibilidade e tamanho
          canvas.toBlob((blob) => {
            if (!blob) {
              resolve(file);
              return;
            }
            const optimizedFile = new File([blob], file.name.replace(/\.[^/.]+$/, ".jpg"), {
              type: 'image/jpeg',
              lastModified: Date.now(),
            });
            resolve(optimizedFile);
          }, 'image/jpeg', 0.7);
        };
        img.onerror = () => resolve(file); // Fallback: envia original se falhar
      };
      reader.onerror = () => resolve(file); // Fallback
    });
  }

  static async submitLead(data: LeadData): Promise<IntegrationResponse> {
    try {
      const formData = new FormData();

      // Ordem dos campos importa para alguns parsers
      formData.append("access_key", this.WEB3FORMS_KEY);
      formData.append("subject", `LEAD (${data.revendedor}): ${data.nome_completo}`);
      formData.append("from_name", "Portal CTNB");
      formData.append("botcheck", ""); 

      // Dados do Lead
      formData.append("Nome", data.nome_completo);
      formData.append("Email", data.email);
      formData.append("Telefone", data.telefone);
      formData.append("Revendedor", data.revendedor);
      formData.append("LGPD", "Aceite Confirmado");
      formData.append("Link WhatsApp", `https://wa.me/55${data.telefone.replace(/\D/g, '')}`);

      // Processamento de Imagem
      if (data.documento) {
        try {
          // Comprime antes de enviar
          const compressedFile = await this.compressImage(data.documento);
          formData.append("attachment", compressedFile);
        } catch (e) {
          // Se falhar compressão, tenta enviar original
          formData.append("attachment", data.documento);
        }
      }

      // Envio sem headers customizados para evitar CORS Preflight (OPTIONS request) que costuma falhar
      const response = await fetch(this.API_ENDPOINT, {
        method: "POST",
        body: formData
      });

      // Se a resposta não for OK, tenta ler o erro
      if (!response.ok) {
        throw new Error(`Servidor respondeu com erro ${response.status}`);
      }

      const result = await response.json();

      if (result.success) {
        return {
          success: true,
          message: "Enviado com sucesso!",
          integrationId: result.id
        };
      } else {
        throw new Error(result.message || "Erro na validação do formulário.");
      }

    } catch (error: any) {
      console.error("[LEAD SERVICE] Erro:", error);

      // Tratamento de erros comuns
      let userMessage = "Falha ao conectar com o servidor.";

      if (error.message.includes('Failed to fetch') || error.message.includes('NetworkError')) {
         userMessage = "Erro de Conexão. Verifique sua internet ou tente desativar bloqueadores de anúncio.";
      } else if (error.message.includes('400') || error.message.includes('validation')) {
         userMessage = "Dados inválidos recusados pelo servidor.";
      }

      return {
        success: false,
        message: userMessage
      };
    }
  }

  static validatePhone(phone: string): boolean {
    const cleanPhone = phone.replace(/\D/g, '');
    return cleanPhone.length >= 10 && cleanPhone.length <= 11;
  }

  static validateEmail(email: string): boolean {
    return /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email);
  }
}

