import { LeadData, IntegrationResponse } from '../types';

export class LeadService {
  private static readonly WEB3FORMS_KEY = "5bdef52f-1212-45a3-8ea3-07a06ae8d2ee";
  private static readonly API_ENDPOINT = "https://api.web3forms.com/submit";

  /**
   * Comprime a imagem de forma AGRESSIVA para garantir que o upload seja instantâneo.
   * Reduz para max 800px e qualidade média.
   */
  private static async compressImage(file: File): Promise<File> {
    return new Promise((resolve) => {
      // Se não for imagem, retorna o arquivo original (mas o input já filtra)
      if (!file.type.match(/image.*/)) {
        resolve(file);
        return;
      }

      const reader = new FileReader();
      reader.readAsDataURL(file);
      reader.onload = (event) => {
        const img = new Image();
        img.src = event.target?.result as string;
        img.onload = () => {
          // Redimensiona para no máximo 800px (Arquivo ficará < 300kb)
          const MAX_DIMENSION = 800;
          let width = img.width;
          let height = img.height;

          if (width > height) {
            if (width > MAX_DIMENSION) {
              height *= MAX_DIMENSION / width;
              width = MAX_DIMENSION;
            }
          } else {
            if (height > MAX_DIMENSION) {
              width *= MAX_DIMENSION / height;
              height = MAX_DIMENSION;
            }
          }

          const canvas = document.createElement('canvas');
          canvas.width = width;
          canvas.height = height;
          const ctx = canvas.getContext('2d');

          if (!ctx) {
            resolve(file); 
            return;
          }

          ctx.drawImage(img, 0, 0, width, height);

          // Qualidade 0.6 para garantir leveza máxima
          canvas.toBlob((blob) => {
            if (!blob) {
              resolve(file);
              return;
            }
            // Renomeia para garantir extensão .jpg
            const cleanName = file.name.split('.')[0].replace(/[^a-z0-9]/gi, '_');
            const optimizedFile = new File([blob], `${cleanName}.jpg`, {
              type: 'image/jpeg',
              lastModified: Date.now(),
            });
            resolve(optimizedFile);
          }, 'image/jpeg', 0.6);
        };
        // Se a imagem falhar ao carregar, envia o original mesmo
        img.onerror = () => resolve(file);
      };
      // Se o FileReader falhar
      reader.onerror = () => resolve(file);
    });
  }

  /**
   * Tenta enviar os dados com mecanismo de retry automático
   */
  static async submitLead(data: LeadData): Promise<IntegrationResponse> {
    let attempts = 0;
    const maxAttempts = 3;

    while (attempts < maxAttempts) {
      try {
        return await this.performSubmission(data);
      } catch (error: any) {
        attempts++;
        console.warn(`Tentativa ${attempts} falhou:`, error);

        // Se for erro de validação (400), não adianta tentar de novo
        if (error.message && (error.message.includes('400') || error.message.includes('inválidos'))) {
          break;
        }

        // Se atingiu o limite, lança o erro final
        if (attempts >= maxAttempts) {
          let userMessage = "Falha de conexão persistente.";

          if (!navigator.onLine) {
            userMessage = "Sem conexão com a internet.";
          } else if (error.message.includes('Failed to fetch')) {
             userMessage = "O envio foi bloqueado pelo navegador ou rede.";
          }

          return {
            success: false,
            message: userMessage
          };
        }

