    // 2. Campos Padrão (Use apenas letras minúsculas)
    formData.append("name", data.nome_completo);
    formData.append("email", data.email);

    // 3. Montagem da Mensagem (O Web3Forms processa melhor um corpo de texto único)
    const messageBody = `
