import { LeadData, IntegrationResponse } from '../types';

export class LeadService {
  private static readonly WEB3FORMS_KEY = "5bdef52f-1212-45a3-8ea3-07a06ae8d2ee";
  private static readonly API_ENDPOINT = "https://api.web3forms.com/submit";

  /**
   * Comprime a imagem.
   */
  private static async compressImage(file: File): Promise<File> {
    return new Promise((resolve) => {
      if (!file.type.match(/image.*/)) {
        resolve(file);
        return;
      }

      const reader = new FileReader();
      reader.readAsDataURL(file);
      reader.onload = (event) => {
        const img = new Image();
        img.src = event.target?.result as string;
        img.onload = () => {
          const MAX_DIMENSION = 800;
          let width = img.width;
          let height = img.height;

          if (width > height) {
            if (width > MAX_DIMENSION) {
              height *= MAX_DIMENSION / width;
              width = MAX_DIMENSION;
            }
          } else {
            if (height > MAX_DIMENSION) {
              width *= MAX_DIMENSION / height;
              height = MAX_DIMENSION;
            }
          }

          const canvas = document.createElement('canvas');
          canvas.width = width;
          canvas.height = height;
          const ctx = canvas.getContext('2d');

          if (!ctx) {
            resolve(file); 
            return;
          }

          ctx.drawImage(img, 0, 0, width, height);

          canvas.toBlob((blob) => {
            if (!blob) {
              resolve(file);
              return;
            }
            const cleanName = file.name.split('.')[0].replace(/[^a-z0-9]/gi, '_');
            const optimizedFile = new File([blob], `${cleanName}.jpg`, {
              type: 'image/jpeg',
              lastModified: Date.now(),
            });
            resolve(optimizedFile);
          }, 'image/jpeg', 0.6);
        };
        img.onerror = () => resolve(file);
      };
      reader.onerror = () => resolve(file);
    });
  }

  static async submitLead(data: LeadData): Promise<IntegrationResponse> {
    const maxAttempts = 3;

    for (let attempt = 0; attempt < maxAttempts; attempt++) {
      try {
        // ESTRATÉGIA DE FALLBACK:
        // Nas tentativas 0 e 1, tentamos enviar TUDO (com anexo).
        // Na tentativa 2 (última), se falhou as anteriores, enviamos SEM ANEXO para garantir o Lead.
        const includeAttachment = attempt < 2; 

        return await this.performSubmission(data, includeAttachment);

      } catch (error: any) {
        console.warn(`Tentativa ${attempt + 1} falhou:`, error);

        // Se for erro de cliente (400), não adianta tentar de novo (dados errados)
        if (error.message && (error.message.includes('400') || error.message.includes('inválidos'))) {
           return { success: false, message: "Dados recusados. Verifique o e-mail informado." };
        }

        // Se for a última tentativa, desistimos e retornamos erro
        if (attempt === maxAttempts - 1) {
          let msg = "Falha de conexão. Tente mais tarde.";
          if (error.message.includes('Failed to fetch')) msg = "Erro de rede ou bloqueador de anúncios detectado.";
          if (error.name === 'AbortError') msg = "O envio demorou muito e expirou.";

          return { success: false, message: msg };
        }

        // Aguarda 1.5s antes de tentar de novo
        await new Promise(r => setTimeout(r, 1500));
      }
    }

    return { success: false, message: "Erro desconhecido." };
  }

  private static async performSubmission(data: LeadData, includeAttachment: boolean): Promise<IntegrationResponse> {
    const formData = new FormData();

    // Configurações API
    formData.append("access_key", this.WEB3FORMS_KEY);
    formData.append("botcheck", ""); 

    // Dados Principais
    formData.append("name", data.nome_completo);
    formData.append("email", data.email);

    // Mensagem detalhada
    let messageBody = `
NOVO LEAD - PORTAL CTNB
=======================
Nome: ${data.nome_completo}
Revendedor: ${data.revendedor}
Telefone: ${data.telefone}
Empresa: ${data.empresa || '-'}
E-mail: ${data.email}
Link WhatsApp: https://wa.me/55${data.telefone.replace(/\D/g, '')}
`;

    if (!includeAttachment && data.documento) {
      messageBody += `\n[ATENÇÃO]: O documento não pôde ser enviado devido a instabilidade na conexão do usuário.`;
    }

    formData.append("message", messageBody.trim());

    // Anexo (Condicional)
    if (includeAttachment && data.documento) {
      try {
        const compressedFile = await this.compressImage(data.documento);
        formData.append("attachment", compressedFile);
      } catch (e) {
        // Se der erro na compressão, ignora o anexo para não quebrar o envio do lead
        console.error("Erro ao processar imagem", e);
      }
    }

    // Configura Timeout de 15 segundos para não travar o app
    const controller = new AbortController();
    const timeoutId = setTimeout(() => controller.abort(), 15000);

    try {
      const response = await fetch(this.API_ENDPOINT, {
        method: "POST",
        body: formData,
        signal: controller.signal
      });

      if (!response.ok) {
        throw new Error(`Erro HTTP: ${response.status}`);
      }

      const result = await response.json();
      if (result.success) {
        return { success: true, message: "Enviado com sucesso!", integrationId: result.id };
      } else {
        throw new Error(result.message || "Erro na API.");
      }
    } finally {
      clearTimeout(timeoutId);
    }
  }

  static validatePhone(phone: string): boolean {
    const cleanPhone = phone.replace(/\D/g, '');
    return cleanPhone.length >= 10 && cleanPhone.length <= 11;
  }

  static validateEmail(email: string): boolean {
    return /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email);
  }
}

