  static async submitLead(data: LeadData): Promise<IntegrationResponse> {
    const maxAttempts = 3;

    for (let attempt = 0; attempt < maxAttempts; attempt++) {
      try {
        // Fallback: Tentativas 0 e 1 tentam enviar com imagem (FormData).
        // Tentativa 2 envia APENAS JSON (texto puro), que é muito mais difícil de falhar.
        const useFormData = attempt < 2 && !!data.documento;

        return await this.performSubmission(data, useFormData);

      } catch (error: any) {
        console.warn(`Tentativa ${attempt + 1} falhou:`, error);

        // Se a API retornou explicitamente que a chave é inválida ou o email bloqueado, paramos.
        // Não mascaramos mais o erro aqui.
        if (error.message && (
             error.message.toLowerCase().includes('access_key') || 
             error.message.toLowerCase().includes('spam') ||
             error.message.toLowerCase().includes('quota')
           )) {
           return { success: false, message: `Erro Fatal: ${error.message}` };
        }

        // Se for a última tentativa, falha geral.
        if (attempt === maxAttempts - 1) {
          let msg = error.message || "Erro desconhecido.";

          if (msg === 'Failed to fetch' || msg.includes('NetworkError')) {
             msg = "Sem conexão. Verifique sua internet.";
          } else if (msg.includes('400')) {
             msg = "Dados inválidos recusados pelo servidor.";
          }

