  }

  private static async performSubmission(data: LeadData, useFormData: boolean): Promise<IntegrationResponse> {
    let body: FormData | string;
    let headers: Record<string, string> = {
      'Accept': 'application/json' // Força resposta JSON para lermos o erro corretamente
    };

    // Construção da Mensagem
    let messageBody = `
NOVO LEAD - PORTAL CTNB
=======================
Nome: ${data.nome_completo}
Revendedor: ${data.revendedor}
Telefone: ${data.telefone}
Empresa: ${data.empresa || '-'}
E-mail: ${data.email}
Link WhatsApp: https://wa.me/55${data.telefone.replace(/\D/g, '')}
`.trim();

