      messageBody += `\n\n[AVISO SISTEMA]: O documento não foi anexado devido a instabilidade de conexão na ponta do usuário. Dados de texto preservados.`;
    }

    // Configuração do Payload (FormData vs JSON)
    if (useFormData) {
      const form = new FormData();
      form.append("access_key", this.WEB3FORMS_KEY);
      form.append("botcheck", ""); 
      form.append("name", data.nome_completo);
      form.append("email", data.email); // Se o email for inválido, Web3Forms recusa aqui
      form.append("message", messageBody);

      try {
        const compressed = await this.compressImage(data.documento!);
        form.append("attachment", compressed);
      } catch (e) {
        console.warn("Falha compressão", e);
        form.append("attachment", data.documento!);
      }
      body = form;
      // Não setar Content-Type para FormData!
    } else {
      // Modo Texto Puro (Muito estável)
      headers['Content-Type'] = 'application/json';
      body = JSON.stringify({
        access_key: this.WEB3FORMS_KEY,
        botcheck: "",
        name: data.nome_completo,
        email: data.email, 
        message: messageBody
      });
    }

    // Timeout Control
    const controller = new AbortController();
    const timeoutId = setTimeout(() => controller.abort(), 15000);

    try {
      const response = await fetch(this.API_ENDPOINT, {
        method: "POST",
        headers: headers,
        body: body,
        signal: controller.signal
      });

      const result = await response.json().catch(() => null);

      if (!response.ok) {
        // Lança o erro EXATO que o servidor mandou (ex: "Invalid Access Key")
        const serverError = result?.message || result?.error || `Erro HTTP ${response.status}`;
        throw new Error(serverError);
      }

      if (result && result.success) {
        return {
          success: true,
          message: "Enviado com sucesso!",
          integrationId: result.id
        };
      } else {
        throw new Error(result?.message || "Erro desconhecido na API");
      }
    } finally {
      clearTimeout(timeoutId);
    }
  }

  static validatePhone(phone: string): boolean {
    const cleanPhone = phone.replace(/\D/g, '');
    return cleanPhone.length >= 10 && cleanPhone.length <= 11;
  }

  static validateEmail(email: string): boolean {
    // Regex mais permissivo para evitar falso negativo no front
    return /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email);
  }
}

