      reader.readAsDataURL(file);
      reader.onload = (event) => {
        const img = new Image();
        img.src = event.target?.result as string;
        img.onload = () => {
          const MAX_DIMENSION = 800;
          let width = img.width;
          let height = img.height;

          if (width > height) {
            if (width > MAX_DIMENSION) {
              height *= MAX_DIMENSION / width;
              width = MAX_DIMENSION;
            }
          } else {
            if (height > MAX_DIMENSION) {
              width *= MAX_DIMENSION / height;
              height = MAX_DIMENSION;
            }
          }

          const canvas = document.createElement('canvas');
          canvas.width = width;
          canvas.height = height;
          const ctx = canvas.getContext('2d');

          if (!ctx) {
            resolve(file); 
            return;
          }

          ctx.drawImage(img, 0, 0, width, height);

          canvas.toBlob((blob) => {
            if (!blob) {
              resolve(file);
              return;
            }
            const cleanName = file.name.split('.')[0].replace(/[^a-z0-9]/gi, '_');
            const optimizedFile = new File([blob], `${cleanName}.jpg`, {
              type: 'image/jpeg',
              lastModified: Date.now(),
            });
            resolve(optimizedFile);
          }, 'image/jpeg', 0.6);
        };
        img.onerror = () => resolve(file);
      };
      reader.onerror = () => resolve(file);
    });
  }

  static async submitLead(data: LeadData): Promise<IntegrationResponse> {
    const maxAttempts = 3;

    for (let attempt = 0; attempt < maxAttempts; attempt++) {
      try {
        // Fallback: Tentativas 0 e 1 tentam enviar com imagem (FormData).
        // Tentativa 2 envia APENAS JSON (texto puro), que é muito mais difícil de falhar.
        const useFormData = attempt < 2 && !!data.documento;

        return await this.performSubmission(data, useFormData);

      } catch (error: any) {
        console.warn(`Tentativa ${attempt + 1} falhou:`, error);

        // Se a API retornou explicitamente que a chave é inválida ou o email bloqueado, paramos.
        if (error.message && (
             error.message.toLowerCase().includes('access_key') || 
             error.message.toLowerCase().includes('spam') ||
             error.message.toLowerCase().includes('quota')
           )) {
           return { success: false, message: `Erro Fatal: ${error.message}` };
        }

        // Se for a última tentativa, falha geral.
        if (attempt === maxAttempts - 1) {
          let msg = error.message || "Erro desconhecido.";

          if (msg === 'Failed to fetch' || msg.includes('NetworkError')) {
             msg = "Sem conexão. Verifique sua internet.";
          } else if (msg.includes('400')) {
             msg = "Dados inválidos recusados pelo servidor.";
          }

          return { success: false, message: msg };
        }

        // Backoff progressivo
        await new Promise(r => setTimeout(r, 1500 * (attempt + 1)));
      }
    }

    return { success: false, message: "Erro de comunicação." };
  }

  private static async performSubmission(data: LeadData, useFormData: boolean): Promise<IntegrationResponse> {
    let body: FormData | string;
    let headers: Record<string, string> = {
      'Accept': 'application/json' 
    };

    // Construção da Mensagem
    let messageBody = `
NOVO LEAD - PORTAL CTNB
=======================
Nome: ${data.nome_completo}
Revendedor: ${data.revendedor}
Telefone: ${data.telefone}
Empresa: ${data.empresa || '-'}
E-mail: ${data.email}
Link WhatsApp: https://wa.me/55${data.telefone.replace(/\D/g, '')}
`.trim();

    if (!useFormData && data.documento) {
      messageBody += `\n\n[AVISO SISTEMA]: O documento não foi anexado devido a instabilidade de conexão na ponta do usuário. Dados de texto preservados.`;
    }

    // Assunto e Nome do Remetente explícitos melhoram a entregabilidade
    const emailSubject = `Novo Lead: ${data.nome_completo} - ${data.revendedor}`;
    const senderName = "Portal CTNB";

    // Configuração do Payload (FormData vs JSON)
    if (useFormData) {
      const form = new FormData();
      form.append("access_key", this.WEB3FORMS_KEY);
      form.append("subject", emailSubject); // Melhora entrega
      form.append("from_name", senderName); // Melhora entrega
      form.append("botcheck", ""); 
      form.append("name", data.nome_completo);
      form.append("email", data.email); 
      form.append("message", messageBody);

      try {
        const compressed = await this.compressImage(data.documento!);
        form.append("attachment", compressed);
      } catch (e) {
        console.warn("Falha compressão", e);
        form.append("attachment", data.documento!);
      }
      body = form;
      // Não setar Content-Type para FormData!
    } else {
      // Modo Texto Puro (Muito estável)
      headers['Content-Type'] = 'application/json';
      body = JSON.stringify({
        access_key: this.WEB3FORMS_KEY,
        subject: emailSubject, // Melhora entrega
        from_name: senderName, // Melhora entrega
        botcheck: "",
        name: data.nome_completo,
        email: data.email, 
        message: messageBody
      });
    }

    // Timeout Control
    const controller = new AbortController();
    const timeoutId = setTimeout(() => controller.abort(), 20000); // Aumentado para 20s para uploads lentos

    try {
      const response = await fetch(this.API_ENDPOINT, {
        method: "POST",
        headers: headers,
        body: body,
        signal: controller.signal
      });

      const result = await response.json().catch(() => null);

      if (!response.ok) {
        const serverError = result?.message || result?.error || `Erro HTTP ${response.status}`;
        throw new Error(serverError);
      }

      if (result && result.success) {
        return {
          success: true,
          message: "Enviado com sucesso!",
          integrationId: result.id
        };
      } else {
        throw new Error(result?.message || "Erro desconhecido na API");
      }
    } finally {
      clearTimeout(timeoutId);
    }
  }

  static validatePhone(phone: string): boolean {
    const cleanPhone = phone.replace(/\D/g, '');
    return cleanPhone.length >= 10 && cleanPhone.length <= 11;
  }

  static validateEmail(email: string): boolean {
    // Regex mais permissivo para evitar falso negativo no front
    return /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email);
  }
}

