  /**
   * Prepara o anexo. Se for imagem, comprime agressivamente. Se for PDF, retorna original.
   * Adicionado timeout para evitar travamentos.
   */
  private static async prepareAttachment(file: File): Promise<File> {
    const COMPRESSION_TIMEOUT = 5000; // 5 segundos max para comprimir

    const compressionTask = new Promise<File>((resolve) => {
      // Se for PDF ou não for imagem (ex: planilha), retorna o arquivo original
      if (file.type === 'application/pdf' || !file.type.startsWith('image/')) {
        resolve(file);
        return;
      }

      const reader = new FileReader();
      reader.readAsDataURL(file);
      reader.onload = (event) => {
        const img = new Image();
        img.src = event.target?.result as string;
        img.onload = () => {
          // Dimensões reduzidas para garantir envio rápido (Mobile First)
          const MAX_DIMENSION = 1000; 
          let width = img.width;
          let height = img.height;

          if (width > height) {
            if (width > MAX_DIMENSION) {
              height *= MAX_DIMENSION / width;
              width = MAX_DIMENSION;
            }
          } else {
            if (height > MAX_DIMENSION) {
              width *= MAX_DIMENSION / height;
              height = MAX_DIMENSION;
            }
          }

          const canvas = document.createElement('canvas');
          canvas.width = width;
          canvas.height = height;
          const ctx = canvas.getContext('2d');

          if (!ctx) {
            resolve(file); 
            return;
          }

          // Fundo branco para imagens transparentes (png/webp) convertidas para jpg
          ctx.fillStyle = '#FFFFFF';
          ctx.fillRect(0, 0, width, height);
          ctx.drawImage(img, 0, 0, width, height);

          // Qualidade 0.7 para equilibrar legibilidade e tamanho de arquivo
          canvas.toBlob((blob) => {
            if (!blob) {
              resolve(file);
              return;
            }
            // Normaliza nome para .jpg para garantir compatibilidade
            const cleanName = file.name.split('.')[0].replace(/[^a-z0-9]/gi, '_');
            const optimizedFile = new File([blob], `${cleanName}.jpg`, {
              type: 'image/jpeg',
              lastModified: Date.now(),
            });
            resolve(optimizedFile);
          }, 'image/jpeg', 0.7); 
        };
        img.onerror = () => resolve(file);
      };
      reader.onerror = () => resolve(file);
    });

    // Race condition: Se a compressão demorar mais que 5s, envia o original
    const timeoutTask = new Promise<File>((resolve) => {
      setTimeout(() => resolve(file), COMPRESSION_TIMEOUT);
    });

    return Promise.race([compressionTask, timeoutTask]);
  }

  static async submitLead(data: LeadData): Promise<IntegrationResponse> {
    const maxAttempts = 3;

    for (let attempt = 0; attempt < maxAttempts; attempt++) {
      try {
        // Fallback: Tentativas 0 e 1 tentam enviar com anexo (FormData).
        // Tentativa 2 envia APENAS JSON (texto puro) se as anteriores falharem.
        const useFormData = attempt < 2 && !!data.documento;

        return await this.performSubmission(data, useFormData);

      } catch (error: any) {
        console.warn(`Tentativa ${attempt + 1} falhou:`, error);

        // Se for erro de cota ou chave, aborta imediatamente
        if (error.message && (
             error.message.toLowerCase().includes('access_key') || 
             error.message.toLowerCase().includes('spam') ||
             error.message.toLowerCase().includes('quota')
           )) {
           return { success: false, message: `Erro Fatal: ${error.message}` };
        }

        // Se for a última tentativa, retorna o erro
        if (attempt === maxAttempts - 1) {
          let msg = error.message || "Erro desconhecido.";

          if (msg === 'Failed to fetch' || msg.includes('NetworkError')) {
             msg = "Sem conexão ou arquivo muito grande. Tente um arquivo menor.";
          } else if (msg.includes('400')) {
             msg = "Dados recusados pelo servidor.";
          }

          return { success: false, message: msg };
        }

        // Backoff exponencial para dar tempo da rede estabilizar (2s, 4s...)
        await new Promise(r => setTimeout(r, 2000 * (attempt + 1)));
      }
    }

    return { success: false, message: "Erro de comunicação." };
  }

