import { LeadData, IntegrationResponse } from '../types';

export class LeadService {
  private static readonly WEB3FORMS_KEY = "3aa90e3e-6bab-496f-b86d-5a5ae7443b1c";
  private static readonly API_ENDPOINT = "https://api.web3forms.com/submit";

  /**
   * Prepara o anexo. Compressão agressiva para evitar timeout.
   */
  private static async prepareAttachment(file: File): Promise<File> {
    const COMPRESSION_TIMEOUT = 4000; // 4 segundos

    const compressionTask = new Promise<File>((resolve) => {
      // Se for PDF ou não imagem, retorna original
      if (file.type === 'application/pdf' || !file.type.startsWith('image/')) {
        resolve(file);
        return;
      }

      const reader = new FileReader();
      reader.readAsDataURL(file);
      reader.onload = (event) => {
        const img = new Image();
        img.src = event.target?.result as string;
        img.onload = () => {
          // Reduzido para 800px para garantir envio em conexões 3G/4G
          const MAX_DIMENSION = 800; 
          let width = img.width;
          let height = img.height;

          if (width > height) {
            if (width > MAX_DIMENSION) {
              height *= MAX_DIMENSION / width;
              width = MAX_DIMENSION;
            }
          } else {
            if (height > MAX_DIMENSION) {
              width *= MAX_DIMENSION / height;
              height = MAX_DIMENSION;
            }
          }

          const canvas = document.createElement('canvas');
          canvas.width = width;
          canvas.height = height;
          const ctx = canvas.getContext('2d');

          if (!ctx) {
            resolve(file); 
            return;
          }

          ctx.fillStyle = '#FFFFFF';
          ctx.fillRect(0, 0, width, height);
          ctx.drawImage(img, 0, 0, width, height);

          // Qualidade 0.6 (60%) para arquivo bem leve
          canvas.toBlob((blob) => {
            if (!blob) {
              resolve(file);
              return;
            }
            const cleanName = file.name.split('.')[0].replace(/[^a-z0-9]/gi, '_');
            const optimizedFile = new File([blob], `${cleanName}.jpg`, {
              type: 'image/jpeg',
              lastModified: Date.now(),
            });
            resolve(optimizedFile);
          }, 'image/jpeg', 0.6); 
        };
        img.onerror = () => resolve(file);
      };
      reader.onerror = () => resolve(file);
    });

    const timeoutTask = new Promise<File>((resolve) => {
      setTimeout(() => resolve(file), COMPRESSION_TIMEOUT);
    });

    return Promise.race([compressionTask, timeoutTask]);
  }

  static async submitLead(data: LeadData): Promise<IntegrationResponse> {
    // ESTRATÉGIA DE RETRY (3 Tentativas):
    // 1. Tenta com anexo e FormData.
    // 2. Se falhar, tenta SEM anexo (FormData), assumindo erro de arquivo.
    // 3. Se falhar, tenta JSON puro (sem anexo) para garantir entrega dos dados.
    const maxAttempts = 3;

    for (let attempt = 0; attempt < maxAttempts; attempt++) {
      try {
        const includeFile = attempt === 0 && !!data.documento;
        const useFormData = attempt < 2;

        return await this.performSubmission(data, useFormData, includeFile);

      } catch (error: any) {
        console.warn(`Tentativa ${attempt + 1} falhou:`, error);

        // Erros fatais
        if (error.message && (
             error.message.toLowerCase().includes('access_key') || 
             error.message.toLowerCase().includes('quota')
           )) {
           return { success: false, message: `Erro Configuração: ${error.message}` };
        }

        if (attempt === maxAttempts - 1) {
           return { 
             success: false, 
             message: "Instabilidade no envio. Tente enviar apenas texto ou contate via WhatsApp." 
           };
        }

        // Aguarda antes de tentar de novo
        await new Promise(r => setTimeout(r, 1500));
      }
    }

    return { success: false, message: "Erro desconhecido." };
  }

  private static async performSubmission(data: LeadData, useFormData: boolean, includeFile: boolean): Promise<IntegrationResponse> {
    let body: FormData | string;
    let headers: Record<string, string> = {
      'Accept': 'application/json' 
    };

    const emailSubject = `Novo Lead: ${data.nome_completo} - ${data.revendedor}`;
    const senderName = "Portal CTNB";

    // Dados estruturados para o template 'table'
    const formPayload: Record<string, string> = {
      "Nome": data.nome_completo,
      "Empresa": data.empresa || "-",
      "Email": data.email,
      "Telefone": data.telefone,
      "Revendedor": data.revendedor,
      "WhatsApp Link": `https://wa.me/55${data.telefone.replace(/\D/g, '')}`,
      "LGPD Aceite": "Sim"
    };

    let messageBody = "Lead capturado via Portal.";
    if (!includeFile && data.documento) {
      messageBody += `\n\n[AVISO]: O documento original (${data.documento.name}) não foi anexado nesta tentativa para garantir a entrega dos dados. Solicite via WhatsApp.`;
    }

    if (useFormData) {
      const form = new FormData();
      form.append("access_key", this.WEB3FORMS_KEY);
      form.append("subject", emailSubject);
      form.append("from_name", senderName);
      form.append("botcheck", ""); 
      form.append("template", "table"); // 'table' é mais robusto que 'box'

      Object.entries(formPayload).forEach(([key, value]) => {
        form.append(key, value);
      });

      form.append("message", messageBody);

      if (includeFile && data.documento) {
        try {
          const attachment = await this.prepareAttachment(data.documento);
          form.append("attachment", attachment);
        } catch (e) {
          // Se falhar preparo, não anexa para não quebrar o request
          console.error("Erro ao preparar arquivo", e);
        }
      }
      body = form;
    } else {
      // JSON Mode
      headers['Content-Type'] = 'application/json';
      body = JSON.stringify({
        access_key: this.WEB3FORMS_KEY,
        subject: emailSubject,
        from_name: senderName,
        botcheck: "",
        template: "table",
        ...formPayload,
        message: messageBody
      });
    }

    const controller = new AbortController();
    // Timeout maior para upload (40s)
    const timeoutId = setTimeout(() => controller.abort(), 40000);

    try {
      const response = await fetch(this.API_ENDPOINT, {
        method: "POST",
        headers: headers,
        body: body,
        signal: controller.signal
      });

      const result = await response.json().catch(() => null);

      if (!response.ok) {
        throw new Error(result?.message || `Erro HTTP ${response.status}`);
      }

      if (result && result.success) {
        return {
          success: true,
          message: "Enviado com sucesso!",
          integrationId: result.id
        };
      } else {
        throw new Error(result?.message || "Falha na API");
      }
    } finally {
      clearTimeout(timeoutId);
    }
  }

  static validatePhone(phone: string): boolean {
    const cleanPhone = phone.replace(/\D/g, '');
    return cleanPhone.length >= 10 && cleanPhone.length <= 11;
  }

  static validateEmail(email: string): boolean {
    return /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email);
  }
}

import { LeadData, IntegrationResponse } from '../types';

export class LeadService {
  private static readonly WEB3FORMS_KEY = "3aa90e3e-6bab-496f-b86d-5a5ae7443b1c";

  // --- CONFIGURAÇÃO DA NUVEM (CLOUDINARY) ---
  // Para produção, crie uma conta grátis no Cloudinary.com
  // Crie um "Unsigned Upload Preset" nas configurações.
  private static readonly CLOUDINARY_CLOUD_NAME = "demo"; // TROQUE PELO SEU (Ex: 'minha-empresa')
  private static readonly CLOUDINARY_UPLOAD_PRESET = "docs_upload_unsigned"; // TROQUE PELO SEU PRESET (Ex: 'ml_default')

  /**
   * Faz o upload do arquivo para a nuvem e retorna a URL pública.
   * Tenta Cloudinary primeiro. Se não configurado, usa File.io (temporário).
   */
  private static async uploadDocument(file: File): Promise<string> {
    try {
      // 1. TENTATIVA CLOUDINARY (Profissional)
      if (this.CLOUDINARY_CLOUD_NAME !== "demo") {
        const formData = new FormData();
        formData.append('file', file);
        formData.append('upload_preset', this.CLOUDINARY_UPLOAD_PRESET);
        // Otimização automática para imagens
        if (file.type.startsWith('image/')) {
            formData.append('transformation', 'w_1200,q_auto,f_auto'); 
        }

        const response = await fetch(
          `https://api.cloudinary.com/v1_1/${this.CLOUDINARY_CLOUD_NAME}/auto/upload`,
          { method: 'POST', body: formData }
        );

        if (response.ok) {
          const data = await response.json();
          return data.secure_url; // Retorna o link permanente
        }
      }

      // 2. FALLBACK PARA FILE.IO (Para testes imediatos)
      // Nota: Arquivos no file.io são deletados após 1 download ou 14 dias.
      const formData = new FormData();
      formData.append('file', file);

      const response = await fetch('https://file.io/?expires=2w', {
        method: 'POST',
        body: formData
      });

      if (response.ok) {
        const data = await response.json();
        return data.link;
      }

      throw new Error("Falha no upload em todos os serviços.");

    } catch (error) {
      console.error("Erro no upload:", error);
      return ""; // Retorna vazio para não travar o envio do lead
    }
  }

  static async submitLead(data: LeadData): Promise<IntegrationResponse> {
    try {
      // PASSO 1: Upload do Documento (Se existir)
      let documentLink = "Não anexado";

      if (data.documento) {
        // Se for PDF ou Imagem, sobe para a nuvem
        documentLink = "Fazendo upload..."; // Placeholder
        const uploadedUrl = await this.uploadDocument(data.documento);

        if (uploadedUrl) {
            documentLink = uploadedUrl;
        } else {
            documentLink = "Falha no upload (solicitar via WhatsApp)";
        }
      }

      // PASSO 2: Preparar E-mail (Apenas Texto/JSON)
      // O envio agora é levíssimo, pois não carrega o binário do arquivo, apenas o link.
      const whatsappLink = `https://wa.me/55${data.telefone.replace(/\D/g, '')}`;

      const formPayload = {
        "Nome do Cliente": data.nome_completo,
        "Empresa": data.empresa || "-",
        "E-mail": data.email,
        "Telefone": data.telefone,
        "Revendedor": data.revendedor,
        "Link Documento": documentLink, // O link aparece clicável no e-mail
        "Link WhatsApp": whatsappLink,
        "Aceite LGPD": "Sim"
      };

      // Template 'table' para visual profissional
      const body = JSON.stringify({
        access_key: this.WEB3FORMS_KEY,
        subject: `Novo Lead: ${data.nome_completo} (${data.revendedor})`,
        from_name: "Portal CTNB",
        template: "table",
        ...formPayload,
        message: data.documento && !documentLink.startsWith('http') 
          ? "⚠️ O arquivo não pôde ser hospedado. Peça ao cliente pelo WhatsApp." 
          : "Documento hospedado com segurança. Clique no link acima para visualizar."
      });

      // PASSO 3: Envio para Web3Forms
      const response = await fetch("https://api.web3forms.com/submit", {
        method: "POST",
        headers: {
          'Content-Type': 'application/json',
          'Accept': 'application/json'
        },
        body: body
      });

      const result = await response.json();

      if (result.success) {
        return { success: true, message: "Lead enviado com sucesso!" };
      } else {
        throw new Error(result.message || "Erro no serviço de e-mail.");
      }

    } catch (error: any) {
      console.error("Erro fatal:", error);
      return { 
        success: false, 
        message: "Erro de conexão. Verifique sua internet." 
      };
    }
  }

  static validatePhone(phone: string): boolean {
    const cleanPhone = phone.replace(/\D/g, '');
    return cleanPhone.length >= 10 && cleanPhone.length <= 11;
  }

  static validateEmail(email: string): boolean {
    return /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email);
  }
}

